import React from 'react';
import './Detail.css';
import { AddBookmarkButton } from './Bookmark';

function Detail({ item, onClose }) {
  if (!item) {
    return null;
  }

  const handleGetDirections = () => {
    const mapUrl = `https://map.kakao.com/link/search/${item.name}`;
    window.location.href = mapUrl;
  };

  return (
    <div className="detail-block">
      <div className="detail">
        <button className="detail-close" onClick={onClose}></button> {/* 닫기 버튼 */}
        <br />
        <img
          id="detail-img"
          alt="detail-img"
          src={item.imageURL} // item 객체에서 이미지 URL을 가져와서 사용
        />
        <h1>{item.name}</h1>
        <p>{item.address}</p>
        <div className="detail-icon">
          {item.stationChargerId && (
            <AddBookmarkButton
              stationChargerId={item.stationChargerId}
              name={item.name}
              address={item.address}
            />
          )}
          <button className="bookmark-button" onClick={() => {
            // Add bookmark logic here
          }}>
            <div className="icon-with-text">
              <img src="bookmark-icon-url" alt="북마크 아이콘" />
              <span>북마크하기</span>
            </div>
          </button>
        </div>
        <span className="location-icon-container">
          <button className="detail-locationicon" onClick={handleGetDirections}>
            <div className="icon-with-text">
              <img src="location-icon-url" alt="위치 아이콘" />
              <span>길찾기</span>
            </div>
          </button>
        </span>
        <hr />
        <p>운영자: {item.operatorName}</p>
        <p>출력: {item.output}</p>
        <p>종류: {item.chargerTypeName}</p>
        <p>{item.kindDetailName}</p>
        <p id="update">업데이트 날짜: {item.updatedAt}</p>
      </div>
    </div>
  );
}

export default Detail;
